const jwt = require('jsonwebtoken');
const { Client } = require('magicbell-js/user-client');
const fs = require('fs');

async function main() {
  const runId = process.env.ZEALT_RUN_ID;
  const magicbellEmail = process.env.MAGICBELL_EMAIL;
  const apiKey = process.env.MAGICBELL_API_KEY;
  const secretKey = process.env.MAGICBELL_SECRET_KEY;

  if (!runId || !magicbellEmail || !apiKey || !secretKey) {
    console.error('Missing environment variables');
    process.exit(1);
  }

  const userEmail = `${magicbellEmail}+${runId}@gmail.com`;

  // Generate User JWT
  const token = jwt.sign({ userEmail }, secretKey, { algorithm: 'HS256' });

  // Initialize Client
  // Note: the UserClient might need both token and apiKey? Wait, in the README it only says { token: 'YOUR_TOKEN' }
  // Wait, does the backend know which project it is from the token alone? No, the secret is unique per project. But normally API key is required too.
  // Let's pass headers if it fails, or just token first.
  const client = new Client({ token });

  // Let's look at how to set headers or api key if needed
  // If we need to pass apiKey, maybe it's { token, apiKey }? 
  // Let's check the constructor of Client in user-client
  client.channels.saveUserPreferences({
    categories: [
      {
        key: 'default',
        channels: [
          {
            name: 'email',
            enabled: false
          }
        ]
      }
    ]
  }).then(() => {
    fs.writeFileSync('/home/user/myproject/output.log', 'Preferences updated.\n');
    console.log('Preferences updated.');
  }).catch(err => {
    console.error(err);
    fs.writeFileSync('/home/user/myproject/output.log', `Error: ${err.message}\n`);
    process.exit(1);
  });
}

main();

